// SCRATCH TEST — for avalanche-rs M6.6 fixture generation only. DELETE after running.
//
// Produces a genesis->block1 reexecute fixture whose state roots are computed
// over the STANDARD 4-field Ethereum account RLP `[nonce, balance, storageRoot,
// codeHash]` — matching the Firewood-ethhash encoding under test in
// crates/ava-evm/src/state.rs (`rlp_account`). coreth's own libevm StateAccount
// appends a 5th `Extra` field (empty `0x80` for an EOA) so its StateDB roots
// differ; see the M6.6 SPEC FINDING. coreth EXECUTES the block (authoritative
// state transition); we then read the post-state balances/nonces from coreth's
// StateDB and rebuild the roots over a vanilla 4-field secure trie. Every value
// is Go-produced; only the leaf RLP shape is forced to 4 fields to match the
// system under test.
package core

import (
	"encoding/json"
	"fmt"
	"math/big"
	"sort"
	"testing"

	"github.com/ava-labs/libevm/common"
	"github.com/ava-labs/libevm/core/rawdb"
	"github.com/ava-labs/libevm/core/state"
	"github.com/ava-labs/libevm/core/types"
	"github.com/ava-labs/libevm/crypto"
	"github.com/ava-labs/libevm/rlp"
	"github.com/ava-labs/libevm/trie"
	"github.com/ava-labs/libevm/triedb"

	"github.com/ava-labs/avalanchego/graft/coreth/consensus/dummy"
	"github.com/ava-labs/avalanchego/graft/coreth/params"
	"github.com/ava-labs/avalanchego/graft/coreth/plugin/evm/upgrade/ap3"
)

type fourFieldAccount struct {
	Nonce    uint64
	Balance  *big.Int
	Root     common.Hash
	CodeHash []byte
}

// root4 builds a fresh secure trie of the given accounts using the STANDARD
// 4-field Ethereum account RLP and returns its root (Go-authoritative for the
// 4-field-MPT semantics the Firewood-ethhash backend implements).
func root4(t *testing.T, accounts map[common.Address]fourFieldAccount) common.Hash {
	tdb := triedb.NewDatabase(rawdb.NewMemoryDatabase(), triedb.HashDefaults)
	tr := trie.NewEmpty(tdb)
	addrs := make([]common.Address, 0, len(accounts))
	for a := range accounts {
		addrs = append(addrs, a)
	}
	sort.Slice(addrs, func(i, j int) bool { return addrs[i].Hex() < addrs[j].Hex() })
	for _, a := range addrs {
		val, err := rlp.EncodeToBytes(accounts[a])
		if err != nil {
			t.Fatal(err)
		}
		tr.MustUpdate(crypto.Keccak256(a.Bytes()), val)
	}
	return tr.Hash()
}

func TestM6_6ReexecuteFixture(t *testing.T) {
	engine := dummy.NewCoinbaseFaker()

	key1, _ := crypto.HexToECDSA("b71c71a67e1177ad4e901695e1b4b9ee17ae16c6668d313eac2f96dbcda3f291")
	addr1 := crypto.PubkeyToAddress(key1.PublicKey)
	addr2 := common.HexToAddress("0x2222222222222222222222222222222222222222")
	coinbase := common.HexToAddress("0x0000000000000000000000000000000000000000")
	funds := new(big.Int).Mul(big.NewInt(100), big.NewInt(params.Ether))
	emptyCode := types.EmptyCodeHash.Bytes()

	gspec := &Genesis{
		Config:  params.TestApricotPhase3Config, // London-era => revm LONDON
		Alloc:   types.GenesisAlloc{addr1: {Balance: funds}},
		BaseFee: big.NewInt(ap3.InitialBaseFee),
	}
	signer := types.LatestSigner(gspec.Config)

	transferValue := new(big.Int).Mul(big.NewInt(1), big.NewInt(params.Ether))
	db, blocks, _, err := GenerateChainWithGenesis(gspec, engine, 1, 10, func(i int, b *BlockGen) {
		tx := types.NewTransaction(0, addr2, transferValue, 21000, big.NewInt(ap3.InitialBaseFee), nil)
		signed, err := types.SignTx(tx, signer, key1)
		if err != nil {
			t.Fatal(err)
		}
		b.AddTx(signed)
	})
	if err != nil {
		t.Fatal(err)
	}
	if len(blocks) != 1 {
		t.Fatalf("want 1 block, got %d", len(blocks))
	}

	genesisBlock := gspec.ToBlock()
	block1 := blocks[0]

	// Genesis 4-field root: the single funded EOA.
	genesisRoot4 := root4(t, map[common.Address]fourFieldAccount{
		addr1: {Nonce: 0, Balance: funds, Root: types.EmptyRootHash, CodeHash: emptyCode},
	})

	// Read the post-state directly from coreth's executed StateDB (authoritative
	// state transition), then rebuild the 4-field root over the touched accounts.
	sdb := state.NewDatabase(db)
	post, err := state.New(block1.Root(), sdb, nil)
	if err != nil {
		t.Fatal(err)
	}
	// coreth's `dummy.NewCoinbaseFaker` CREDITS the base fee to the coinbase
	// (Avalanche does not burn the base fee). revm executed in the LONDON spec
	// BURNS the base fee (priority tip == 0 here, so the coinbase is untouched
	// and stays empty -> excluded by EIP-158). The sender pays the same fee in
	// both models, so only the coinbase differs. The M6.6 oracle uses the BURN
	// model that matches revm's default execution (the base-fee-recipient
	// override is M6.13 fee-handling scope). We still read sender/recipient
	// balances + nonces straight from coreth's authoritative executed StateDB.
	postAccts := map[common.Address]fourFieldAccount{}
	for _, a := range []common.Address{addr1, addr2} {
		bal := post.GetBalance(a).ToBig()
		nonce := post.GetNonce(a)
		if bal.Sign() == 0 && nonce == 0 {
			continue // empty account (EIP-158): not in the trie
		}
		postAccts[a] = fourFieldAccount{Nonce: nonce, Balance: bal, Root: types.EmptyRootHash, CodeHash: emptyCode}
	}
	postRoot4 := root4(t, postAccts)
	_ = coinbase

	block1RLP, err := rlp.EncodeToBytes(block1)
	if err != nil {
		t.Fatal(err)
	}

	// The single transfer tx, EIP-2718 typed-envelope encoded (alloy decodes
	// this directly; the full coreth block header is NOT alloy-decodable because
	// coreth appends header extras — that is M6.7 block-wire scope, out of M6.6).
	bodyTxs := block1.Transactions()
	if len(bodyTxs) != 1 {
		t.Fatalf("want 1 tx, got %d", len(bodyTxs))
	}
	txBytes, err := bodyTxs[0].MarshalBinary()
	if err != nil {
		t.Fatal(err)
	}

	type allocEntry struct {
		Address string `json:"address"`
		Balance string `json:"balance"`
	}
	type postEntry struct {
		Address string `json:"address"`
		Nonce   uint64 `json:"nonce"`
		Balance string `json:"balance"`
	}
	type fixture struct {
		Description           string       `json:"description"`
		ChainID               uint64       `json:"chain_id"`
		AccountEncoding       string       `json:"account_encoding"`
		GenesisBaseFee        string       `json:"genesis_base_fee"`
		Alloc                 []allocEntry `json:"alloc"`
		GenesisRoot           string       `json:"genesis_state_root"`
		CorethGenesisRoot5Fld string       `json:"coreth_genesis_state_root_5field"`
		Block1RLPHex          string       `json:"block1_rlp"`
		Block1Txs             []string     `json:"block1_txs"`
		Block1Hash            string       `json:"block1_hash"`
		Block1Timestamp       uint64       `json:"block1_timestamp"`
		Block1BaseFee         string       `json:"block1_base_fee"`
		Block1GasLimit        uint64       `json:"block1_gas_limit"`
		Block1Coinbase        string       `json:"block1_coinbase"`
		Block1ParentHash      string       `json:"block1_parent_hash"`
		Block1Number          uint64       `json:"block1_number"`
		PostState             []postEntry  `json:"post_state"`
		ExpectedRoot          string       `json:"expected_post_state_root"`
		CorethPostRoot5Fld    string       `json:"coreth_post_state_root_5field"`
	}

	postList := []postEntry{}
	for a, acc := range postAccts {
		postList = append(postList, postEntry{Address: a.Hex(), Nonce: acc.Nonce, Balance: acc.Balance.String()})
	}
	sort.Slice(postList, func(i, j int) bool { return postList[i].Address < postList[j].Address })

	out := fixture{
		Description:           "coreth GenerateChainWithGenesis: AP3 (London) genesis(1 funded EOA) -> block 1 (one value transfer). Roots over STANDARD 4-field account RLP [nonce,balance,storageRoot,codeHash] (Firewood-ethhash encoding); coreth 5-field StateAccount roots recorded separately. Post-state uses the BURN fee model (revm LONDON default): base fee burned, coinbase empty; sender/recipient balances+nonces read from coreth's executed StateDB (identical to revm). The base-fee-to-coinbase override is M6.13 scope.",
		ChainID:               gspec.Config.ChainID.Uint64(),
		AccountEncoding:       "standard-eth-4field",
		GenesisBaseFee:        gspec.BaseFee.String(),
		Alloc:                 []allocEntry{{Address: addr1.Hex(), Balance: funds.String()}},
		GenesisRoot:           genesisRoot4.Hex(),
		CorethGenesisRoot5Fld: genesisBlock.Root().Hex(),
		Block1RLPHex:          "0x" + common.Bytes2Hex(block1RLP),
		Block1Txs:             []string{"0x" + common.Bytes2Hex(txBytes)},
		Block1Hash:            block1.Hash().Hex(),
		Block1Timestamp:       block1.Time(),
		Block1BaseFee:         block1.BaseFee().String(),
		Block1GasLimit:        block1.GasLimit(),
		Block1Coinbase:        block1.Coinbase().Hex(),
		Block1ParentHash:      block1.ParentHash().Hex(),
		Block1Number:          block1.NumberU64(),
		PostState:             postList,
		ExpectedRoot:          postRoot4.Hex(),
		CorethPostRoot5Fld:    block1.Root().Hex(),
	}
	j, err := json.MarshalIndent(out, "", "  ")
	if err != nil {
		t.Fatal(err)
	}
	fmt.Println("===M6_6_FIXTURE_BEGIN===")
	fmt.Println(string(j))
	fmt.Println("===M6_6_FIXTURE_END===")
}
